// ==============================================================
// WF8 — Buscar empregado no RM (autocomplete) — via AIONS API
// Entrada:  ?nome=<string> (mínimo 3 caracteres)
// Saída:    { resultados: [{nome, chapa, cpf, funcao, admissao, secao, codcoligada}, ...] }
// SQL:      "BEN 2" via POST /consultar-rm (AIONS).
// ==============================================================

const nomeRaw = ($json.query?.nome || '').toString().trim();

if (nomeRaw.length < 3) {
  return [{
    json: {
      _statusCode: 200,
      _skip: true,
      resultados: []
    }
  }];
}

const nomeLike = `%${nomeRaw}%`;

return [{
  json: {
    nomeRaw,
    nomeLike
  }
}];

// ==============================================================
// WF8 — Normaliza resposta do RM em shape camelCase
// Mapeamento dos campos do BEN 2:
//   'Nome do Intermitente'  → nome
//   'Matrícula/Chapa'       → chapa
//   'Seção'                 → secao
//   'Descrição Seção'       → descricaoSecao
//   'Função'                → funcao
//   'Data de Admissão'      → admissao (YYYY-MM-DD)
// CPF: BEN 2 atual não retorna CPF — fica vazio.
//      Se ampliar a consulta SQL, basta mapear 'CPF' aqui.
//
// Nota: o HTTP Request do n8n quebra a resposta JSON-array do RM
//       em N items (1 por linha). Por isso iteramos $input.all().
// ==============================================================

function normalizaAdmissao(v) {
  if (!v) return '';
  const s = String(v).trim();
  // "YYYY-MM-DD HH:mm:ss" → "YYYY-MM-DD"
  const m = s.match(/^(\d{4}-\d{2}-\d{2})/);
  if (m) return m[1];
  // "DD/MM/YYYY" → "YYYY-MM-DD"
  const m2 = s.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
  if (m2) return `${m2[3]}-${m2[2]}-${m2[1]}`;
  return s;
}

function extrairLinhas(item) {
  const j = item?.json;
  if (!j) return [];
  if (Array.isArray(j)) return j;
  if (Array.isArray(j.body)) return j.body;
  if (Array.isArray(j.value)) return j.value;
  if (Array.isArray(j.data)) return j.data;
  // single-row?
  if (j['Nome do Intermitente'] || j['Matrícula/Chapa'] || j.nome) return [j];
  return [];
}

const todos = $input.all();
const linhas = todos.flatMap(extrairLinhas);

const resultados = linhas
  .map((r) => ({
    nome: String(r['Nome do Intermitente'] || r.nome || '').trim(),
    chapa: String(r['Matrícula/Chapa'] || r.chapa || '').trim(),
    cpf: String(r['CPF'] || r.cpf || '').trim(),
    funcao: String(r['Função'] || r.funcao || '').trim(),
    admissao: normalizaAdmissao(r['Data de Admissão'] || r.admissao),
    secao: String(r['Seção'] || r.secao || '').trim(),
    descricaoSecao: String(r['Descrição Seção'] || r.descricaoSecao || '').trim(),
    codcoligada: 3
  }))
  .filter((e) => e.nome.length > 0);

// Dedup por chapa (caso BEN 2 retorne linhas duplicadas)
const vistos = new Set();
const dedup = [];
for (const r of resultados) {
  const key = r.chapa || r.nome;
  if (vistos.has(key)) continue;
  vistos.add(key);
  dedup.push(r);
}

return [{
  json: {
    _statusCode: 200,
    resultados: dedup
  }
}];
